// POST /energy-efficiency-check  — Check NCC energy efficiency requirements for a building
app.post("/energy-efficiency-check", apiKeyAuth, (req, res) => {
  const { jobId, buildingClass, climate, wallRValue, ceilingRValue, floorRValue, glazingUValue, glazingArea, floorArea, heatingSystem, coolingSystem, hotWaterSystem, notes } = req.body || {};
  if (!buildingClass) return res.status(400).json({ error: "buildingClass required." });

  const safeJobId = jobId ? sanitiseInput(String(jobId)).slice(0, 80) : null;
  const safeClass = sanitiseInput(String(buildingClass)).slice(0, 20);
  const safeClimate = climate ? sanitiseInput(String(climate)).slice(0, 50) : "Melbourne";

  // NCC 2022 Climate Zone 6 (Melbourne) minimum R-values
  const CLIMATE_REQUIREMENTS = {
    "melbourne": { wall: 2.0, ceiling: 4.1, floor: 1.0, glazingU: 3.5 },
    "sydney":    { wall: 1.5, ceiling: 3.7, floor: 1.0, glazingU: 4.0 },
    "brisbane":  { wall: 1.0, ceiling: 3.2, floor: 0.5, glazingU: 4.5 },
    "perth":     { wall: 2.0, ceiling: 3.7, floor: 1.0, glazingU: 3.5 },
    "adelaide":  { wall: 2.5, ceiling: 4.1, floor: 1.5, glazingU: 3.0 },
  };

  const climate_key = Object.keys(CLIMATE_REQUIREMENTS).find(k => safeClimate.toLowerCase().includes(k)) || "melbourne";
  const reqs = CLIMATE_REQUIREMENTS[climate_key];

  const wallR    = wallRValue ? parseFloat(wallRValue) : null;
  const ceilingR = ceilingRValue ? parseFloat(ceilingRValue) : null;
  const floorR   = floorRValue ? parseFloat(floorRValue) : null;
  const glazU    = glazingUValue ? parseFloat(glazingUValue) : null;

  const checks = [];
  if (wallR !== null)    checks.push({ item: "Wall R-value",     required: `≥${reqs.wall}`,     provided: wallR,    passed: wallR >= reqs.wall });
  if (ceilingR !== null) checks.push({ item: "Ceiling R-value",  required: `≥${reqs.ceiling}`,  provided: ceilingR, passed: ceilingR >= reqs.ceiling });
  if (floorR !== null)   checks.push({ item: "Floor R-value",    required: `≥${reqs.floor}`,    provided: floorR,   passed: floorR >= reqs.floor });
  if (glazU !== null)    checks.push({ item: "Glazing U-value",  required: `≤${reqs.glazingU}`, provided: glazU,    passed: glazU <= reqs.glazingU });

  const passed  = checks.length > 0 && checks.every(c => c.passed);
  const safeNotes = notes ? sanitiseInput(String(notes)).slice(0, 200) : null;

  return res.json({
    jobId: safeJobId, buildingClass: safeClass, climate: safeClimate,
    climateZone: climate_key,
    checks, compliant: passed,
    failures: checks.filter(c => !c.passed).map(c => `${c.item}: provided ${c.provided} — required ${c.required}`),
    notes: safeNotes,
    standard: "NCC 2022 Section J — Energy Efficiency",
    disclaimer: "Indicative check only. Full NatHERS or JV3 assessment may be required.",
    calculatedAt: new Date().toISOString(),
  });
});

// POST /fire-rating-check  — Check fire resistance level requirements for construction
app.post("/fire-rating-check", apiKeyAuth, (req, res) => {
  const { jobId, buildingClass, buildingType, floors, distanceFromBoundaryM, construction, notes } = req.body || {};
  if (!buildingClass) return res.status(400).json({ error: "buildingClass required." });

  const safeJobId  = jobId ? sanitiseInput(String(jobId)).slice(0, 80) : null;
  const safeClass  = sanitiseInput(String(buildingClass)).toUpperCase().slice(0, 5);
  const safeType   = buildingType ? sanitiseInput(String(buildingType)).slice(0, 60) : null;
  const floorCount = Math.max(1, parseInt(floors) || 1);
  const boundary   = distanceFromBoundaryM ? Math.max(0, parseFloat(distanceFromBoundaryM) || 0) : null;
  const safeCons   = construction ? sanitiseInput(String(construction)).slice(0, 80) : null;

  // Simplified NCC fire requirements (indicative only)
  const TYPE_REQUIREMENTS = {
    "TYPE_A": { description: "Fully fire-resisting", wallFRL: "120/120/120", columnFRL: "120/120/120", beamFRL: "120/120/120", floorFRL: "120/120/120" },
    "TYPE_B": { description: "Fire-protected timber",  wallFRL: "90/90/90",  columnFRL: "90/90/90",  beamFRL: "90/90/90",  floorFRL: "90/90/90"  },
    "TYPE_C": { description: "Non-combustible",        wallFRL: "60/60/60",  columnFRL: "60/60/60",  beamFRL: "60/60/60",  floorFRL: "60/60/60"  },
  };

  let typeKey = "TYPE_C";
  if (floorCount >= 4 || ["1", "2", "3"].some(c => safeClass.includes(c))) typeKey = "TYPE_A";
  else if (floorCount >= 3) typeKey = "TYPE_B";

  const requirements = TYPE_REQUIREMENTS[typeKey];
  const boundaryReq  = boundary !== null && boundary < 3 ? "External walls must have FRL of 90/90/90 to boundary" : null;

  const safeNotes = notes ? sanitiseInput(String(notes)).slice(0, 200) : null;
  return res.json({
    jobId: safeJobId, buildingClass: safeClass, buildingType: safeType,
    floors: floorCount, distanceFromBoundaryM: boundary, construction: safeCons,
    constructionType: typeKey, description: requirements.description,
    requirements: {
      externalWallFRL:   requirements.wallFRL,
      columnFRL:         requirements.columnFRL,
      beamFRL:           requirements.beamFRL,
      floorCeilingFRL:   requirements.floorFRL,
      boundaryRequirement: boundaryReq,
    },
    notes: safeNotes,
    disclaimer: "Indicative only. A fire engineer must verify all FRL requirements under NCC 2022.",
    standard: "NCC 2022 Spec 5 — Fire-resisting construction",
    calculatedAt: new Date().toISOString(),
  });
});

// POST /accessibility-check  — Check AS 1428 accessibility compliance
app.post("/accessibility-check", apiKeyAuth, (req, res) => {
  const { jobId, spaceType, doorWidthMm, corridorWidthMm, rampGradient, handrailHeight, toiletAccessible, parkingBays, notes } = req.body || {};
  if (!spaceType) return res.status(400).json({ error: "spaceType required." });

  const safeJobId   = jobId ? sanitiseInput(String(jobId)).slice(0, 80) : null;
  const safeType    = sanitiseInput(String(spaceType)).slice(0, 60);
  const safeNotes   = notes ? sanitiseInput(String(notes)).slice(0, 200) : null;

  const doorW   = doorWidthMm ? parseInt(doorWidthMm) : null;
  const corrW   = corridorWidthMm ? parseInt(corridorWidthMm) : null;
  const ramp    = rampGradient ? parseFloat(rampGradient) : null;
  const handrail = handrailHeight ? parseInt(handrailHeight) : null;

  const checks = [];
  if (doorW !== null)    checks.push({ item: "Doorway clear width",      required: "≥850mm",  provided: `${doorW}mm`,     passed: doorW >= 850,  standard: "AS 1428.1 cl 7.2" });
  if (corrW !== null)    checks.push({ item: "Corridor clear width",     required: "≥1000mm", provided: `${corrW}mm`,     passed: corrW >= 1000, standard: "AS 1428.1 cl 7.4" });
  if (ramp !== null)     checks.push({ item: "Ramp gradient",            required: "≤1:14",   provided: `1:${ramp}`,      passed: ramp >= 14,    standard: "AS 1428.1 cl 8.1" });
  if (handrail !== null) checks.push({ item: "Handrail height",          required: "865-1000mm", provided: `${handrail}mm`, passed: handrail >= 865 && handrail <= 1000, standard: "AS 1428.1 cl 10.4" });
  if (toiletAccessible !== undefined) checks.push({ item: "Accessible toilet provided", required: "Yes", provided: toiletAccessible ? "Yes" : "No", passed: toiletAccessible === true, standard: "AS 1428.1" });

  const compliant = checks.length > 0 && checks.every(c => c.passed);
  return res.json({
    jobId: safeJobId, spaceType: safeType,
    checks, compliant,
    failures: checks.filter(c => !c.passed).map(c => `${c.item}: ${c.provided} does not meet ${c.required} (${c.standard})`),
    notes: safeNotes, standard: "AS 1428.1:2021 — Design for access and mobility",
    calculatedAt: new Date().toISOString(),
  });
});

// GET /ncc-requirements/:buildingClass  — Get NCC requirements summary for a building class
app.get("/ncc-requirements/:buildingClass", apiKeyAuth, (req, res) => {
  const buildingClass = sanitiseInput(String(req.params.buildingClass || "")).toUpperCase().replace(/\s/g, "");

  const NCC_CLASSES = {
    "1A": { name: "Single dwelling — house or townhouse", typical: "residential house or attached dwelling", applications: ["New homes", "Alterations/additions", "Granny flats"], keyRequirements: ["NCC Section H — Residential provisions", "Bushfire attack level if in BAL zone", "Energy efficiency (NatHERS 7-star rating)", "Condensation management", "Livable housing design (if applicable)"] },
    "1B": { name: "3+ dwellings on one allotment", typical: "residential flats or boarding house", applications: ["Boarding houses", "Guest houses", "4+ bed residential buildings"], keyRequirements: ["Fire separation between dwellings", "Exit provisions", "Energy efficiency", "Disability access"] },
    "2":  { name: "Multi-unit residential building", typical: "apartments or units above ground level", applications: ["Apartment blocks", "Strata title units"], keyRequirements: ["Fire resistance — Type A or B construction", "Lift requirements", "Smoke detection in common areas", "Exit design", "Disability access"] },
    "3":  { name: "Hotel/motel/residential buildings (other)", typical: "hotels, boarding houses, backpacker accommodation", applications: ["Hotels", "Motels", "Hostels"], keyRequirements: ["Smoke detection in all rooms", "Exit lighting", "Fire sprinklers above 3 storeys", "Disability access"] },
    "5":  { name: "Office buildings", typical: "commercial office space", applications: ["Corporate offices", "Professional suites"], keyRequirements: ["Lifts if >25m rise", "Fire safety systems", "Disability access", "Energy efficiency (Section J)"] },
    "6":  { name: "Retail/shop", typical: "shops, cafes, restaurants, markets", applications: ["Retail shops", "Food and drink premises"], keyRequirements: ["Public area accessibility", "Emergency lighting", "Exit signage", "Food safety for commercial kitchens"] },
    "7A": { name: "Carpark", typical: "car park", applications: ["Public/private carparks"], keyRequirements: ["Ventilation", "Fire separation", "Structural loading"] },
    "7B": { name: "Storage/warehouse", typical: "warehouse or storage facility", applications: ["Warehouses", "Self-storage"], keyRequirements: ["Exit provisions", "Fire sprinklers if >2000m²", "Dangerous goods if applicable"] },
    "8":  { name: "Factory/industrial", typical: "factory, laboratory, laundry", applications: ["Manufacturing", "Food processing"], keyRequirements: ["Exit design", "Ventilation", "Hazardous area classification if applicable"] },
    "10A": { name: "Shed/garage/carport", typical: "non-habitable structure", applications: ["Domestic sheds", "Carports"], keyRequirements: ["Setback requirements", "Site coverage", "Council DCP may apply"] },
    "10B": { name: "Swimming pool / fence", typical: "pool or fence", applications: ["Swimming pools", "Spas"], keyRequirements: ["AS 1926.1 pool safety barriers", "CPR sign required", "Pool fencing heights and gate requirements"] },
  };

  const info = NCC_CLASSES[buildingClass] || null;
  if (!info) {
    return res.json({ buildingClass, info: null, message: `Class not found. Available: ${Object.keys(NCC_CLASSES).join(", ")}` });
  }

  return res.json({ buildingClass, ...info, note: "Summary only. Consult NCC 2022 and local council DCP for complete requirements.", generatedAt: new Date().toISOString() });
});

// POST /ai-ncc-query  — AI answers a question about NCC building requirements
app.post("/ai-ncc-query", apiKeyAuth, async (req, res) => {
  const { question, buildingClass, state = "VIC" } = req.body || {};
  if (!question) return res.status(400).json({ error: "question required." });

  const safeQ      = sanitiseInput(String(question)).slice(0, 500);
  const safeClass  = buildingClass ? sanitiseInput(String(buildingClass)).toUpperCase().slice(0, 5) : null;
  const safeState  = sanitiseInput(String(state)).toUpperCase().slice(0, 5);

  const prompt = `You are an NCC 2022 (National Construction Code) expert for Australia, with specific knowledge of ${safeState} state variations.

Question about: ${safeClass ? `Building Class ${safeClass}` : "general building requirements"}
State: ${safeState}
Question: ${safeQ}

Provide a clear, accurate answer in JSON:
{
  "answer": "clear answer to the question",
  "relevantSections": ["NCC section or clause reference"],
  "keyPoints": ["key point 1", "key point 2"],
  "stateVariations": "any VIC/state-specific variation",
  "disclaimer": "standard disclaimer about professional advice"
}`;

  try {
    const aiRes = await callOpenAIWithRetry([{ role: "user", content: prompt }], { response_format: { type: "json_object" }, max_tokens: 600 });
    const parsed = JSON.parse(aiRes.choices[0].message.content);
    usageStats.openaiCalls++;
    return res.json({
      question: safeQ, buildingClass: safeClass, state: safeState,
      answer:           parsed.answer || "Unable to answer at this time.",
      relevantSections: Array.isArray(parsed.relevantSections) ? parsed.relevantSections : [],
      keyPoints:        Array.isArray(parsed.keyPoints) ? parsed.keyPoints : [],
      stateVariations:  parsed.stateVariations || null,
      disclaimer: parsed.disclaimer || "This is AI-generated guidance only. Consult a registered building practitioner or certifier for formal advice.",
      generatedAt: new Date().toISOString(),
    });
  } catch (_) {
    return res.json({
      question: safeQ, buildingClass: safeClass, state: safeState,
      answer: "NCC query service temporarily unavailable. Consult ncc.abcb.gov.au for authoritative information.",
      relevantSections: [], keyPoints: [], stateVariations: null,
      disclaimer: "Consult a registered building practitioner or certifier for formal advice.",
      generatedAt: new Date().toISOString(),
    });
  }
});

// GET /public-holidays/:year  — Get Victorian public holidays for a given year
app.get("/public-holidays/:year", apiKeyAuth, (req, res) => {
  const year = parseInt(req.params.year) || new Date().getFullYear();
  if (year < 2020 || year > 2030) return res.status(400).json({ error: "Year must be between 2020 and 2030." });

  const state  = (req.query.state || "VIC").toUpperCase();

  // Victorian public holidays (fixed + calculated)
  const holidays = [
    { name: "New Year's Day",         date: `${year}-01-01`, type: "public" },
    { name: "Australia Day",          date: `${year}-01-26`, type: "public" },
    { name: "Labour Day (VIC)",       date: getSecondMondayMarch(year), type: "public" },
    { name: "Good Friday",            date: getGoodFriday(year), type: "public" },
    { name: "Easter Saturday",        date: addDays(getGoodFriday(year), 1), type: "public" },
    { name: "Easter Sunday",          date: addDays(getGoodFriday(year), 2), type: "public" },
    { name: "Easter Monday",          date: addDays(getGoodFriday(year), 3), type: "public" },
    { name: "ANZAC Day",              date: `${year}-04-25`, type: "public" },
    { name: "King's Birthday (VIC)",  date: getSecondMondayJune(year),  type: "public" },
    { name: "AFL Grand Final Friday", date: getAFLGrandFinalFriday(year), type: "public" },
    { name: "Melbourne Cup Day",      date: getFirstTuesdayNovember(year), type: "public" },
    { name: "Christmas Day",          date: `${year}-12-25`, type: "public" },
    { name: "Boxing Day",             date: `${year}-12-26`, type: "public" },
  ].sort((a, b) => a.date.localeCompare(b.date));

  function getGoodFriday(y) {
    // Anonymous Gregorian algorithm
    const a = y % 19, b = Math.floor(y / 100), c = y % 100;
    const d = Math.floor(b / 4), e = b % 4, f = Math.floor((b + 8) / 25);
    const g = Math.floor((b - f + 1) / 3), h = (19 * a + b - d - g + 15) % 30;
    const i = Math.floor(c / 4), k = c % 4;
    const l = (32 + 2 * e + 2 * i - h - k) % 7;
    const m = Math.floor((a + 11 * h + 22 * l) / 451);
    const month = Math.floor((h + l - 7 * m + 114) / 31);
    const day   = ((h + l - 7 * m + 114) % 31) + 1;
    const easter = new Date(y, month - 1, day);
    easter.setDate(easter.getDate() - 2);
    return easter.toISOString().split("T")[0];
  }
  function addDays(dateStr, n) { const d = new Date(dateStr); d.setDate(d.getDate() + n); return d.toISOString().split("T")[0]; }
  function getNthWeekdayOfMonth(y, month, weekday, n) {
    const d = new Date(y, month - 1, 1); let count = 0;
    while (count < n) { if (d.getDay() === weekday) count++; if (count < n) d.setDate(d.getDate() + 1); }
    return d.toISOString().split("T")[0];
  }
  function getSecondMondayMarch(y) { return getNthWeekdayOfMonth(y, 3, 1, 2); }
  function getSecondMondayJune(y)  { return getNthWeekdayOfMonth(y, 6, 1, 2); }
  function getFirstTuesdayNovember(y) { return getNthWeekdayOfMonth(y, 11, 2, 1); }
  function getAFLGrandFinalFriday(y) {
    // Typically last Friday of September, but varies — return an estimate
    const d = new Date(y, 8, 30); while (d.getDay() !== 5) d.setDate(d.getDate() - 1); return d.toISOString().split("T")[0];
  }

  return res.json({ year, state: state === "VIC" ? "VIC" : "VIC (only VIC supported)", count: holidays.length, holidays, note: "AFL Grand Final Friday and some dates may vary — always verify with the Victorian Government.", generatedAt: new Date().toISOString() });
});

// POST /hot-work-permit  — Log a hot work permit (welding, grinding, cutting, soldering)
app.post("/hot-work-permit", apiKeyAuth, async (req, res) => {
  const { siteId, jobId, location, workType, operator, supervisedBy, startTime, endTime, fireWatcherName, fireWatcherDurationMinutes, hotWorkChecks = [], notes } = req.body || {};
  if (!siteId && !jobId) return res.status(400).json({ error: "siteId or jobId required." });
  if (!workType) return res.status(400).json({ error: "workType required." });

  const VALID_TYPES = ["welding", "grinding", "cutting", "soldering", "brazing", "torch", "other"];
  const safeSiteId = siteId ? sanitiseInput(String(siteId)).slice(0, 80) : null;
  const safeJobId  = jobId ? sanitiseInput(String(jobId)).slice(0, 80) : null;
  const safeLoc    = location ? sanitiseInput(String(location)).slice(0, 150) : null;
  const safeType   = VALID_TYPES.includes(String(workType).toLowerCase()) ? String(workType).toLowerCase() : "other";
  const safeOp     = operator ? sanitiseInput(String(operator)).slice(0, 100) : null;
  const safeSup    = supervisedBy ? sanitiseInput(String(supervisedBy)).slice(0, 100) : null;
  const safeWatcher = fireWatcherName ? sanitiseInput(String(fireWatcherName)).slice(0, 100) : null;
  const watchMins  = Math.max(0, parseInt(fireWatcherDurationMinutes) || 30);
  const safeNotes  = notes ? sanitiseInput(String(notes)).slice(0, 300) : null;

  const DEFAULT_CHECKS = [
    "Combustible materials removed or protected within 10m",
    "Fire extinguisher within 10m",
    "Fire watch person nominated",
    "Sprinkler system checked (not isolated)",
    "Smoke detectors near work area — covered/isolated as required",
    "Proper PPE worn (welding mask, gloves, apron)",
    "Hot work approved by site supervisor",
  ];
  const allChecks = (Array.isArray(hotWorkChecks) && hotWorkChecks.length > 0)
    ? hotWorkChecks.slice(0, 20).map(c => ({ item: sanitiseInput(String(c.item || c)).slice(0, 150), done: c.done !== false }))
    : DEFAULT_CHECKS.map(c => ({ item: c, done: true }));

  const permit = {
    permitId: `HWP-${(safeSiteId || safeJobId).slice(0, 6).toUpperCase()}-${Date.now().toString(36).toUpperCase()}`,
    siteId: safeSiteId, jobId: safeJobId, location: safeLoc, workType: safeType,
    operator: safeOp, supervisedBy: safeSup,
    startTime: startTime ? sanitiseInput(String(startTime)).slice(0, 20) : new Date().toISOString(),
    endTime:   endTime ? sanitiseInput(String(endTime)).slice(0, 20) : null,
    fireWatcher: safeWatcher, fireWatchDurationMinutes: watchMins,
    checks: allChecks, allChecksPassed: allChecks.every(c => c.done),
    status: "ACTIVE", notes: safeNotes,
    issuedAt: new Date().toISOString(),
  };

  if (supabaseAdmin) {
    try {
      await supabaseAdmin.from("hot_work_permits").insert({
        permit_id: permit.permitId, site_id: safeSiteId, job_id: safeJobId, location: safeLoc,
        work_type: safeType, operator: safeOp, supervised_by: safeSup,
        start_time: permit.startTime, end_time: permit.endTime,
        fire_watcher: safeWatcher, fire_watch_duration_minutes: watchMins,
        checks: allChecks, status: "ACTIVE", notes: safeNotes, issued_at: permit.issuedAt,
      });
    } catch (_) { /* non-critical */ }
  }

  return res.status(201).json({ ...permit, saved: !!supabaseAdmin });
});

// POST /ai-quote-review  — AI reviews a supplier/subcontractor quote for reasonableness
app.post("/ai-quote-review", apiKeyAuth, async (req, res) => {
  const { jobType, quoteAmount, lineItems = [], scope, state = "VIC", urgency } = req.body || {};
  if (!jobType || !quoteAmount) return res.status(400).json({ error: "jobType and quoteAmount required." });

  const safeType   = sanitiseInput(String(jobType)).slice(0, 40);
  const safeAmount = Math.max(0, parseFloat(quoteAmount) || 0);
  const safeScope  = scope ? sanitiseInput(String(scope)).slice(0, 1000) : null;
  const safeState  = sanitiseInput(String(state)).toUpperCase().slice(0, 5);
  const safeUrgency = urgency ? sanitiseInput(String(urgency)).slice(0, 30) : null;
  const safeItems  = Array.isArray(lineItems) ? lineItems.slice(0, 20).map(i => sanitiseInput(String(i)).slice(0, 150)) : [];

  const prompt = `You are a ${safeType} trade estimator and procurement expert in ${safeState}, Australia.

Review the following quote:
Total amount: $${safeAmount.toLocaleString()}
${safeScope ? `Scope: ${safeScope}` : ""}
${safeItems.length > 0 ? `Line items: ${safeItems.join(", ")}` : ""}
${safeUrgency ? `Urgency: ${safeUrgency}` : ""}

Assess this quote in JSON:
{
  "verdict": "GOOD_VALUE|FAIR|OVERPRICED|POTENTIALLY_LOW",
  "marketPosition": "LOW|AVERAGE|HIGH",
  "concerns": ["concern1"],
  "missingItems": ["item likely missing from quote"],
  "negotiationPoints": ["area to negotiate"],
  "recommendation": "brief recommendation",
  "confidenceLevel": "LOW|MEDIUM|HIGH"
}`;

  try {
    const aiRes = await callOpenAIWithRetry([{ role: "user", content: prompt }], { response_format: { type: "json_object" }, max_tokens: 500 });
    const parsed = JSON.parse(aiRes.choices[0].message.content);
    usageStats.openaiCalls++;
    return res.json({
      jobType: safeType, quoteAmount: safeAmount, state: safeState,
      verdict:            parsed.verdict || "FAIR",
      marketPosition:     parsed.marketPosition || "AVERAGE",
      concerns:           Array.isArray(parsed.concerns) ? parsed.concerns : [],
      missingItems:       Array.isArray(parsed.missingItems) ? parsed.missingItems : [],
      negotiationPoints:  Array.isArray(parsed.negotiationPoints) ? parsed.negotiationPoints : [],
      recommendation:     parsed.recommendation || "",
      confidenceLevel:    ["LOW", "MEDIUM", "HIGH"].includes(parsed.confidenceLevel) ? parsed.confidenceLevel : "MEDIUM",
      disclaimer: "AI analysis only. Obtain at least 3 quotes before accepting.",
      generatedAt: new Date().toISOString(),
    });
  } catch (_) {
    return res.json({
      jobType: safeType, quoteAmount: safeAmount, verdict: "FAIR", marketPosition: "AVERAGE",
      concerns: [], missingItems: [], negotiationPoints: [],
      recommendation: "Quote review temporarily unavailable. Compare with at least 3 quotes.",
      confidenceLevel: "LOW",
      disclaimer: "AI analysis only. Obtain at least 3 quotes before accepting.",
      generatedAt: new Date().toISOString(),
    });
  }
});

// POST /dewatering-log  — Log a groundwater/dewatering management event during excavation
app.post("/dewatering-log", apiKeyAuth, async (req, res) => {
  const { siteId, jobId, logDate, groundwaterDepthM, dewateringMethod, pumpRateLpm, dischargeLocation, turbidity, waterQualityOk, councilNotified, notes } = req.body || {};
  if (!siteId && !jobId) return res.status(400).json({ error: "siteId or jobId required." });

  const VALID_METHODS = ["sump-pump", "wellpoint", "deepwell", "sheet-piling", "cut-off-wall", "gravity", "other"];
  const VALID_DISCHARGE = ["sewer", "stormwater", "sediment-basin", "tanker", "land", "other"];

  const safeSiteId = siteId ? sanitiseInput(String(siteId)).slice(0, 80) : null;
  const safeJobId  = jobId ? sanitiseInput(String(jobId)).slice(0, 80) : null;
  const safeDate   = logDate ? sanitiseInput(String(logDate)).slice(0, 20) : new Date().toISOString().split("T")[0];
  const safeMethod = VALID_METHODS.includes(String(dewateringMethod || "").toLowerCase().replace(/ /g, "-")) ? String(dewateringMethod).toLowerCase().replace(/ /g, "-") : "sump-pump";
  const safeDisch  = VALID_DISCHARGE.includes(String(dischargeLocation || "").toLowerCase()) ? String(dischargeLocation).toLowerCase() : "sediment-basin";
  const safeNotes  = notes ? sanitiseInput(String(notes)).slice(0, 300) : null;
  const gwDepth    = groundwaterDepthM ? Math.max(0, parseFloat(groundwaterDepthM) || 0) : null;
  const pumpRate   = pumpRateLpm ? Math.max(0, parseFloat(pumpRateLpm) || 0) : null;
  const turbid     = turbidity ? sanitiseInput(String(turbidity)).slice(0, 30) : null;
  const waterOk    = waterQualityOk !== false;

  const warnings = [];
  if (!waterOk) warnings.push("Poor water quality — do not discharge to stormwater without treatment");
  if (safeDisch === "stormwater" && !waterOk) warnings.push("EPA notification may be required for contaminated groundwater discharge");
  if (safeDisch === "sewer") warnings.push("Trade waste agreement may be required for sewer discharge");

  const record = {
    logId: `DWL-${(safeSiteId || safeJobId).slice(0, 6).toUpperCase()}-${Date.now().toString(36).toUpperCase()}`,
    siteId: safeSiteId, jobId: safeJobId, logDate: safeDate,
    groundwaterDepthM: gwDepth, dewateringMethod: safeMethod, pumpRateLpm: pumpRate,
    dischargeLocation: safeDisch, turbidity: turbid, waterQualityOk: waterOk,
    councilNotified: councilNotified === true, warnings, notes: safeNotes,
    createdAt: new Date().toISOString(),
  };

  if (supabaseAdmin) {
    try {
      await supabaseAdmin.from("dewatering_log").insert({
        log_id: record.logId, site_id: safeSiteId, job_id: safeJobId, log_date: safeDate,
        groundwater_depth_m: gwDepth, dewatering_method: safeMethod, pump_rate_lpm: pumpRate,
        discharge_location: safeDisch, turbidity: turbid, water_quality_ok: waterOk,
        council_notified: record.councilNotified, warnings, notes: safeNotes, created_at: record.createdAt,
      });
    } catch (_) { /* non-critical */ }
  }

  return res.status(201).json({ ...record, saved: !!supabaseAdmin });
});

// POST /excavation-permit  — Log an excavation/Dial Before You Dig permit record
app.post("/excavation-permit", apiKeyAuth, async (req, res) => {
  const { siteId, jobId, address, dbydEnquiryNumber, excavationDate, excavationDepthM, excavationArea, servicesLocated, utilityCompanies = [], safeExcavationZone, supervisor, notes } = req.body || {};
  if (!siteId && !jobId) return res.status(400).json({ error: "siteId or jobId required." });
  if (!dbydEnquiryNumber) return res.status(400).json({ error: "dbydEnquiryNumber required." });

  const safeSiteId = siteId ? sanitiseInput(String(siteId)).slice(0, 80) : null;
  const safeJobId  = jobId ? sanitiseInput(String(jobId)).slice(0, 80) : null;
  const safeEnquiry = sanitiseInput(String(dbydEnquiryNumber)).slice(0, 40);
  const safeDate   = excavationDate ? sanitiseInput(String(excavationDate)).slice(0, 20) : new Date().toISOString().split("T")[0];
  const safeDepth  = excavationDepthM ? Math.max(0, parseFloat(excavationDepthM) || 0) : null;
  const safeArea   = excavationArea ? sanitiseInput(String(excavationArea)).slice(0, 100) : null;
  const safeSup    = supervisor ? sanitiseInput(String(supervisor)).slice(0, 100) : null;
  const safeNotes  = notes ? sanitiseInput(String(notes)).slice(0, 300) : null;
  const safeUtils  = Array.isArray(utilityCompanies) ? utilityCompanies.slice(0, 20).map(u => sanitiseInput(String(u)).slice(0, 80)) : [];
  const safeZone   = safeExcavationZone ? sanitiseInput(String(safeExcavationZone)).slice(0, 200) : null;

  const requirements = [];
  if (safeDepth && safeDepth > 0.3) requirements.push("Manual potholing required within safe excavation zone (SZ)");
  if (safeDepth && safeDepth > 1.5)  requirements.push("Shoring/batter required for excavation >1.5m deep");
  if (safeDepth && safeDepth > 2.0)  requirements.push("WorkSafe notification may be required for excavation >2m");
  requirements.push("Maintain 500mm exclusion zone around all located services");
  requirements.push("Do not use mechanical excavation within SZ without approval from service owner");

  const record = {
    permitId: `EXC-${(safeSiteId || safeJobId).slice(0, 6).toUpperCase()}-${Date.now().toString(36).toUpperCase()}`,
    siteId: safeSiteId, jobId: safeJobId,
    address: address ? sanitiseInput(String(address)).slice(0, 200) : null,
    dbydEnquiryNumber: safeEnquiry, excavationDate: safeDate,
    excavationDepthM: safeDepth, excavationArea: safeArea,
    servicesLocated: servicesLocated === true, utilityCompanies: safeUtils,
    safeExcavationZone: safeZone, supervisor: safeSup,
    requirements, notes: safeNotes, status: "ACTIVE",
    createdAt: new Date().toISOString(),
  };

  if (supabaseAdmin) {
    try {
      await supabaseAdmin.from("excavation_permits").insert({
        permit_id: record.permitId, site_id: safeSiteId, job_id: safeJobId, address: record.address,
        dbyd_enquiry_number: safeEnquiry, excavation_date: safeDate, excavation_depth_m: safeDepth,
        services_located: record.servicesLocated, utility_companies: safeUtils,
        supervisor: safeSup, notes: safeNotes, status: "ACTIVE", created_at: record.createdAt,
      });
    } catch (_) { /* non-critical */ }
  }

  return res.status(201).json({ ...record, saved: !!supabaseAdmin });
});

// POST /underground-services  — Log underground service locations from DBYD results
app.post("/underground-services", apiKeyAuth, async (req, res) => {
  const { siteId, jobId, address, services = [] } = req.body || {};
  if (!siteId && !jobId) return res.status(400).json({ error: "siteId or jobId required." });

  const SERVICE_TYPES = ["gas", "water", "sewer", "electrical", "telecommunications", "stormwater", "traffic-signals", "other"];
  const ACCURACY_TYPES = ["located-marked", "approximate", "unknown", "no-assets"];

  const safeSiteId = siteId ? sanitiseInput(String(siteId)).slice(0, 80) : null;
  const safeJobId  = jobId ? sanitiseInput(String(jobId)).slice(0, 80) : null;
  const safeAddress = address ? sanitiseInput(String(address)).slice(0, 200) : null;

  const logged = services.slice(0, 30).map(s => ({
    serviceType: SERVICE_TYPES.includes(String(s.serviceType || "").toLowerCase().replace(/ /g, "-")) ? String(s.serviceType).toLowerCase().replace(/ /g, "-") : "other",
    owner:       s.owner ? sanitiseInput(String(s.owner)).slice(0, 100) : null,
    depth:       s.depthM ? Math.max(0, parseFloat(s.depthM) || 0) : null,
    accuracy:    ACCURACY_TYPES.includes(String(s.accuracy || "").toLowerCase().replace(/ /g, "-")) ? String(s.accuracy).toLowerCase().replace(/ /g, "-") : "approximate",
    location:    s.location ? sanitiseInput(String(s.location)).slice(0, 200) : null,
    notes:       s.notes ? sanitiseInput(String(s.notes)).slice(0, 150) : null,
  }));

  if (supabaseAdmin) {
    try {
      await supabaseAdmin.from("underground_services").upsert(
        logged.map(s => ({ site_id: safeSiteId, job_id: safeJobId, address: safeAddress, ...s, updated_at: new Date().toISOString() })),
        { onConflict: "site_id,service_type,owner" }
      );
    } catch (_) { /* non-critical */ }
  }

  const hasGas  = logged.some(s => s.serviceType === "gas");
  const hasElec = logged.some(s => s.serviceType === "electrical");
  const warnings = [];
  if (hasGas)  warnings.push("Gas service present — maintain 500mm exclusion zone, contact ATCO/AGN before any excavation");
  if (hasElec) warnings.push("Electrical service present — do not excavate within 600mm without DNSPs approval");

  return res.json({ siteId: safeSiteId, jobId: safeJobId, address: safeAddress, serviceCount: logged.length, warnings, services: logged, savedAt: new Date().toISOString() });
});

// POST /tree-protection  — Log tree protection zones for a site
app.post("/tree-protection", apiKeyAuth, async (req, res) => {
  const { siteId, address, trees = [], counciApprovalRequired, tppRequired, notes } = req.body || {};
  if (!siteId) return res.status(400).json({ error: "siteId required." });

  const safeSiteId = sanitiseInput(String(siteId)).slice(0, 80);
  const safeAddress = address ? sanitiseInput(String(address)).slice(0, 200) : null;
  const safeNotes  = notes ? sanitiseInput(String(notes)).slice(0, 300) : null;

  const treeData = trees.slice(0, 50).map(t => {
    const trunk    = Math.max(0, parseFloat(t.trunkDiameterMm) || 0);
    const tpzM     = parseFloat((trunk / 1000 * 12).toFixed(1)); // TPZ radius = 12 × diameter (m)
    const srpM     = parseFloat((trunk / 1000 * 8).toFixed(1));  // SRP radius = 8 × diameter (m)
    return {
      species:          t.species ? sanitiseInput(String(t.species)).slice(0, 100) : "Unknown",
      trunkDiameterMm:  trunk,
      tpzRadiusM:       tpzM,   // Tree Protection Zone
      srpRadiusM:       srpM,   // Structural Root Zone
      significant:      trunk >= 300 || t.significant === true,
      notes:            t.notes ? sanitiseInput(String(t.notes)).slice(0, 150) : null,
    };
  });

  const significantCount = treeData.filter(t => t.significant).length;
  if (supabaseAdmin) {
    try {
      await supabaseAdmin.from("tree_protection").insert({
        site_id: safeSiteId, address: safeAddress, trees: treeData,
        significant_count: significantCount, council_approval_required: counciApprovalRequired === true,
        tpp_required: tppRequired === true, notes: safeNotes, created_at: new Date().toISOString(),
      });
    } catch (_) { /* non-critical */ }
  }

  return res.json({
    siteId: safeSiteId, address: safeAddress, treeCount: treeData.length, significantCount,
    councilApprovalRequired: counciApprovalRequired === true, tppRequired: tppRequired === true,
    trees: treeData, notes: safeNotes,
    reminder: "Do not undertake works within TPZ without council arborist approval.",
    savedAt: new Date().toISOString(),
  });
});

// POST /site-clean-checklist  — Log a site cleanliness and housekeeping checklist
app.post("/site-clean-checklist", apiKeyAuth, async (req, res) => {
  const { siteId, jobId, inspectedBy, inspectionDate, items = [], overallRating, notes } = req.body || {};
  if (!siteId && !jobId) return res.status(400).json({ error: "siteId or jobId required." });

  const DEFAULT_ITEMS = [
    "Walkways clear of debris and trip hazards", "Materials stored in designated areas",
    "Waste disposed of in bins (not scattered on site)", "Hazardous materials secured and labelled",
    "Tools stored safely when not in use", "Site entrance clean and clearly marked",
    "First aid kit accessible and stocked", "No standing water or mud hazards",
    "Portable toilets serviced and clean", "Security fencing intact",
  ];
  const VALID_RATINGS = ["EXCELLENT", "GOOD", "FAIR", "POOR", "UNACCEPTABLE"];

  const safeSiteId = siteId ? sanitiseInput(String(siteId)).slice(0, 80) : null;
  const safeJobId  = jobId ? sanitiseInput(String(jobId)).slice(0, 80) : null;
  const safeBy     = inspectedBy ? sanitiseInput(String(inspectedBy)).slice(0, 100) : null;
  const safeDate   = inspectionDate ? sanitiseInput(String(inspectionDate)).slice(0, 20) : new Date().toISOString().split("T")[0];
  const safeNotes  = notes ? sanitiseInput(String(notes)).slice(0, 300) : null;
  const safeRating = VALID_RATINGS.includes(String(overallRating || "").toUpperCase()) ? String(overallRating).toUpperCase() : null;

  const checkItems = (Array.isArray(items) && items.length > 0)
    ? items.slice(0, 30).map(i => ({ item: sanitiseInput(String(i.item || i)).slice(0, 150), passed: i.passed !== false }))
    : DEFAULT_ITEMS.map(i => ({ item: i, passed: true }));

  const passCount = checkItems.filter(c => c.passed).length;
  const pct       = Math.round((passCount / checkItems.length) * 100);
  const autoRating = pct >= 90 ? "EXCELLENT" : pct >= 75 ? "GOOD" : pct >= 60 ? "FAIR" : pct >= 40 ? "POOR" : "UNACCEPTABLE";

  const record = {
    checkId: `SCC-${(safeSiteId || safeJobId).slice(0, 6).toUpperCase()}-${Date.now().toString(36).toUpperCase()}`,
    siteId: safeSiteId, jobId: safeJobId, inspectedBy: safeBy, inspectionDate: safeDate,
    items: checkItems, passCount, totalItems: checkItems.length, passPercent: pct,
    rating: safeRating || autoRating, notes: safeNotes,
    createdAt: new Date().toISOString(),
  };

  if (supabaseAdmin) {
    try {
      await supabaseAdmin.from("site_clean_checklists").insert({
        check_id: record.checkId, site_id: safeSiteId, job_id: safeJobId, inspected_by: safeBy,
        inspection_date: safeDate, items: checkItems, pass_count: passCount,
        rating: record.rating, notes: safeNotes, created_at: record.createdAt,
      });
    } catch (_) { /* non-critical */ }
  }

  return res.status(201).json({ ...record, saved: !!supabaseAdmin });
});

// POST /material-delivery  — Log a material delivery to site
app.post("/material-delivery", apiKeyAuth, async (req, res) => {
  const { siteId, jobId, deliveryDate, supplier, deliveryNote, items = [], receivedBy, conditionOnArrival, notes } = req.body || {};
  if (!siteId && !jobId) return res.status(400).json({ error: "siteId or jobId required." });
  if (!Array.isArray(items) || items.length === 0) return res.status(400).json({ error: "items array required." });

  const VALID_CONDITIONS = ["good", "damaged", "partial", "incorrect"];
  const safeSiteId = siteId ? sanitiseInput(String(siteId)).slice(0, 80) : null;
  const safeJobId  = jobId ? sanitiseInput(String(jobId)).slice(0, 80) : null;
  const safeDate   = deliveryDate ? sanitiseInput(String(deliveryDate)).slice(0, 20) : new Date().toISOString().split("T")[0];
  const safeSupplier = supplier ? sanitiseInput(String(supplier)).slice(0, 150) : null;
  const safeDN     = deliveryNote ? sanitiseInput(String(deliveryNote)).slice(0, 80) : null;
  const safeBy     = receivedBy ? sanitiseInput(String(receivedBy)).slice(0, 100) : null;
  const safeCond   = VALID_CONDITIONS.includes(String(conditionOnArrival || "").toLowerCase()) ? String(conditionOnArrival).toLowerCase() : "good";
  const safeNotes  = notes ? sanitiseInput(String(notes)).slice(0, 300) : null;

  const deliveredItems = items.slice(0, 100).map(i => ({
    description: sanitiseInput(String(i.description || "")).slice(0, 150),
    quantity:    Math.max(0, parseFloat(i.quantity) || 0),
    unit:        i.unit ? sanitiseInput(String(i.unit)).slice(0, 20) : "ea",
    condition:   VALID_CONDITIONS.includes(String(i.condition || "").toLowerCase()) ? String(i.condition).toLowerCase() : "good",
    notes:       i.notes ? sanitiseInput(String(i.notes)).slice(0, 100) : null,
  }));

  const damaged = deliveredItems.filter(i => i.condition === "damaged" || i.condition === "incorrect").length;
  const record = {
    deliveryId: `DEL-${(safeSiteId || safeJobId).slice(0, 6).toUpperCase()}-${Date.now().toString(36).toUpperCase()}`,
    siteId: safeSiteId, jobId: safeJobId, deliveryDate: safeDate, supplier: safeSupplier,
    deliveryNote: safeDN, itemCount: deliveredItems.length, damagedItems: damaged,
    overallCondition: safeCond, receivedBy: safeBy, items: deliveredItems, notes: safeNotes,
    hasIssues: damaged > 0 || safeCond !== "good",
    createdAt: new Date().toISOString(),
  };

  if (supabaseAdmin) {
    try {
      await supabaseAdmin.from("material_deliveries").insert({
        delivery_id: record.deliveryId, site_id: safeSiteId, job_id: safeJobId,
        delivery_date: safeDate, supplier: safeSupplier, delivery_note: safeDN,
        items: deliveredItems, overall_condition: safeCond, received_by: safeBy,
        has_issues: record.hasIssues, notes: safeNotes, created_at: record.createdAt,
      });
    } catch (_) { /* non-critical */ }
  }

  return res.status(201).json({ ...record, saved: !!supabaseAdmin });
});

// GET /material-delivery/:siteId  — Get material deliveries for a site
app.get("/material-delivery/:siteId", apiKeyAuth, async (req, res) => {
  const siteId  = sanitiseInput(String(req.params.siteId || "")).slice(0, 80);
  const fromDate = req.query.from ? sanitiseInput(String(req.query.from)).slice(0, 20) : null;
  if (!siteId) return res.status(400).json({ error: "siteId required." });

  let deliveries = [];
  if (supabaseAdmin) {
    try {
      let q = supabaseAdmin.from("material_deliveries").select("*").eq("site_id", siteId).order("delivery_date", { ascending: false }).limit(100);
      if (fromDate) q = q.gte("delivery_date", fromDate);
      const { data } = await q;
      deliveries = data || [];
    } catch (_) { /* ignore */ }
  }

  const issues = deliveries.filter(d => d.has_issues).length;
  return res.json({ siteId, deliveryCount: deliveries.length, deliveriesWithIssues: issues, deliveries, generatedAt: new Date().toISOString() });
});

