// POST /ai-steel-inspection — AI assesses steel inspection results
app.post("/ai-steel-inspection", apiKeyAuth, async (req, res) => {
  const {
    memberType, steelGrade, defectsFound = [], weldDefects = [],
    dimensionalVariances = [], surfaceCondition = "ACCEPTABLE",
    coatingThicknessUM, specifiedCoatingUM,
    ndtResults = [], drawingConformance = true,
    erectingNotes = [], applicableStandard = "AS 4100",
  } = req.body;
  if (!memberType) {
    return res.status(400).json({ error: "memberType is required." });
  }
  const sanitisedMember = sanitiseInput(memberType);
  const sanitisedGrade = sanitiseInput(steelGrade || "Unknown");
  const sanitisedStandard = sanitiseInput(applicableStandard);
  const systemPrompt = `You are an Australian structural steel inspection specialist with expertise in AS 4100 and fabrication quality.`;
  const userPrompt = `Assess structural steel inspection results for:
Member type: ${sanitisedMember}
Steel grade: ${sanitisedGrade}
Applicable standard: ${sanitisedStandard}
Structural defects: ${defectsFound.map(d => sanitiseInput(d)).join("; ") || "None reported"}
Weld defects: ${weldDefects.map(d => sanitiseInput(d)).join("; ") || "None reported"}
Dimensional variances: ${dimensionalVariances.map(v => sanitiseInput(v)).join("; ") || "None reported"}
Surface condition: ${sanitiseInput(surfaceCondition)}
Coating thickness: ${coatingThicknessUM ? `${coatingThicknessUM} μm (specified: ${specifiedCoatingUM} μm)` : "Not measured"}
NDT results: ${ndtResults.map(r => sanitiseInput(r)).join("; ") || "None performed"}
Drawing conformance: ${drawingConformance}
Erection notes: ${erectingNotes.map(n => sanitiseInput(n)).join("; ") || "None"}

Return JSON with:
{
  "overallAssessment": "ACCEPTABLE|CONDITIONAL|REJECT",
  "criticalDefects": ["...", "..."],
  "minorDefects": ["...", "..."],
  "rectificationRequired": ["...", "..."],
  "holdPointStatus": "...",
  "applicableTolerances": {"dimensional": "...", "weld": "...", "coating": "..."},
  "complianceNotes": "...",
  "recommendation": "...",
  "engineerSignOffRequired": false,
  "nextActions": ["...", "..."]
}`;
  try {
    const aiRes = await callOpenAIWithRetry({
      model: "gpt-4.1-mini",
      messages: [
        { role: "system", content: systemPrompt },
        { role: "user", content: userPrompt },
      ],
      response_format: { type: "json_object" },
      max_tokens: 1500,
    });
    usageStats.openaiCalls++;
    const assessment = JSON.parse(aiRes.choices[0].message.content);
    res.json({ memberType: sanitisedMember, steelGrade: sanitisedGrade, applicableStandard: sanitisedStandard, assessment });
  } catch (err) {
    console.error("ai-steel-inspection error:", err.message);
    const hasDefects = defectsFound.length > 0 || weldDefects.length > 0;
    res.json({
      memberType: sanitisedMember, steelGrade: sanitisedGrade, applicableStandard: sanitisedStandard,
      assessment: {
        overallAssessment: hasDefects ? "CONDITIONAL" : "ACCEPTABLE",
        criticalDefects: [],
        minorDefects: defectsFound.concat(weldDefects),
        rectificationRequired: hasDefects ? ["Assess and rectify all identified defects before hold point release"] : [],
        holdPointStatus: hasDefects ? "HOLD — defects require assessment before release" : "Release conditionally — subject to documentation",
        applicableTolerances: { dimensional: "AS 4100 — refer Table 14.4", weld: "AS/NZS 1554 — refer acceptance criteria", coating: "AS 3715 or project specification" },
        complianceNotes: `${sanitisedStandard} compliance assessment required.`,
        recommendation: hasDefects ? "Engage structural engineer or CWI to assess defects." : "Proceed to erection, ensure documentation complete.",
        engineerSignOffRequired: hasDefects,
        nextActions: ["Complete inspection documentation", "Release hold point if all criteria met", "Update shop drawing register"],
      },
    });
  }
});

// POST /drainage-inspection-record — Record a CCTV drain camera inspection
app.post("/drainage-inspection-record", apiKeyAuth, async (req, res) => {
  const {
    propertyAddress, projectId, inspectionDate, operatorName,
    pipeType, pipeDiameterMm, pipeLengthM, pipeAge_years,
    inspectionMethod = "CCTV", flowDirection, conditions = [],
    defectsFound = [], blockageFound = false, blockageLocation,
    blockageType, overallConditionGrade, cleaningRequired = false,
    repairMethod, urgency = "ROUTINE", reportRef, videoRef, notes,
  } = req.body;
  if (!propertyAddress || !inspectionDate || !operatorName) {
    return res.status(400).json({ error: "propertyAddress, inspectionDate, and operatorName are required." });
  }
  const validMethods = ["CCTV", "PUSH_CAMERA", "SONAR", "VISUAL", "SMOKE_TEST", "DYE_TEST"];
  const validUrgencies = ["EMERGENCY", "URGENT", "ROUTINE", "PLANNED"];
  const validGrades = ["A", "B", "C", "D", "E"];
  if (!validMethods.includes(inspectionMethod)) return res.status(400).json({ error: `inspectionMethod must be one of: ${validMethods.join(", ")}` });
  if (!validUrgencies.includes(urgency)) return res.status(400).json({ error: `urgency must be one of: ${validUrgencies.join(", ")}` });
  if (overallConditionGrade && !validGrades.includes(overallConditionGrade)) {
    return res.status(400).json({ error: `overallConditionGrade must be one of: ${validGrades.join(", ")}` });
  }
  const inspectionRef = `DCI-${Date.now().toString(36).toUpperCase()}`;
  const structuralRisk = overallConditionGrade === "D" || overallConditionGrade === "E"
    || defectsFound.some(d => String(d).toLowerCase().includes("collapse") || String(d).toLowerCase().includes("fracture"))
    ? "HIGH" : defectsFound.length > 0 ? "MEDIUM" : "LOW";
  const record = {
    inspection_ref: inspectionRef,
    property_address: sanitiseInput(propertyAddress),
    project_id: projectId || null,
    inspection_date: inspectionDate,
    operator_name: sanitiseInput(operatorName),
    pipe_type: sanitiseInput(pipeType || ""),
    pipe_diameter_mm: Number(pipeDiameterMm) || null,
    pipe_length_m: Number(pipeLengthM) || null,
    pipe_age_years: Number(pipeAge_years) || null,
    inspection_method: inspectionMethod,
    flow_direction: sanitiseInput(flowDirection || ""),
    conditions: Array.isArray(conditions) ? conditions.map(c => sanitiseInput(c)) : [],
    defects_found: Array.isArray(defectsFound) ? defectsFound.map(d => sanitiseInput(d)) : [],
    blockage_found: Boolean(blockageFound),
    blockage_location: sanitiseInput(blockageLocation || ""),
    blockage_type: sanitiseInput(blockageType || ""),
    overall_condition_grade: overallConditionGrade || null,
    cleaning_required: Boolean(cleaningRequired),
    repair_method: sanitiseInput(repairMethod || ""),
    urgency,
    structural_risk: structuralRisk,
    report_ref: sanitiseInput(reportRef || ""),
    video_ref: sanitiseInput(videoRef || ""),
    notes: sanitiseInput(notes || ""),
    created_at: new Date().toISOString(),
  };
  if (supabaseAdmin) {
    const { error } = await supabaseAdmin.from("drainage_inspections").insert(record);
    if (error) console.error("drainage-inspection-record DB error:", error.message);
  }
  res.json({
    inspectionRef, inspectionMethod, overallConditionGrade, structuralRisk,
    defectCount: record.defects_found.length, blockageFound, urgency,
    saved: !!supabaseAdmin,
  });
});

