      drawing_category: sanitiseInput(drawingCategory || ""),
      related_purchase_order: sanitiseInput(relatedPurchaseOrder || ""),
      reviewed_by: sanitiseInput(reviewedBy || ""),
      review_date: reviewDate || null,
