// POST /ai-contract-risk-assessment — AI assesses construction contract risk and key obligations
app.post("/ai-contract-risk-assessment", apiKeyAuth, async (req, res) => {
  try {
    const {
      contractType,
      projectValue,
      contractDuration,
      ownerType,
      keyRisks,
      contractConditions,
      paymentTerms,
      retentionPercent,
      liquidatedDamages,
      extensionOfTimeProvisions,
      variationRights,
      disputeResolution,
      securityAmount,
    } = req.body;

    if (!contractType || !projectValue) {
      return res.status(400).json({ error: "contractType and projectValue are required" });
    }

    const prompt = `You are a construction contract lawyer and project manager with expertise in Victorian construction contracts, SOPA Victoria, DBI Act 1995, and Australian Standard contract forms (AS 4000, AS 4902, HIA, MBA).

Assess contract risk for:
- Contract type: ${sanitiseInput(contractType)}
- Project value: ${sanitiseInput(String(projectValue))}
- Duration: ${sanitiseInput(contractDuration || "not specified")}
- Owner type: ${sanitiseInput(ownerType || "private")}
- Key risks identified: ${sanitiseInput(keyRisks || "not specified")}
- Contract conditions: ${sanitiseInput(contractConditions || "Australian Standard")}
- Payment terms: ${sanitiseInput(paymentTerms || "monthly progress claims")}
- Retention: ${sanitiseInput(String(retentionPercent || "5"))}%
- Liquidated damages: ${sanitiseInput(liquidatedDamages || "not specified")}
- Extension of time provisions: ${sanitiseInput(extensionOfTimeProvisions || "standard")}
- Variation rights: ${sanitiseInput(variationRights || "standard")}
- Dispute resolution: ${sanitiseInput(disputeResolution || "adjudication/arbitration")}
- Security: ${sanitiseInput(securityAmount || "not specified")}

Return a JSON object with:
{
  "riskRating": "LOW|MEDIUM|HIGH|EXTREME",
  "keyContractRisks": [string],
  "sopaObligations": string,
  "paymentRisks": string,
  "timeRisks": string,
  "variationRisks": string,
  "securityObligations": string,
  "disputeResolutionAdvice": string,
  "onusOfProofIssues": string,
  "recommendedContracts": [string],
  "preContractActions": [string],
  "applicableLegislation": [string],
  "recommendation": string,
  "summary": string
}`;

    const aiRes = await callOpenAIWithRetry({
      model: "gpt-4.1-mini",
      messages: [{ role: "user", content: prompt }],
      response_format: { type: "json_object" },
      max_tokens: 900,
    });
    usageStats.openaiCalls++;
    const assessment = JSON.parse(aiRes.choices[0].message.content);

    res.json({ contractType, projectValue, assessment });
  } catch (err) {
    console.error("/ai-contract-risk-assessment error:", err.message);
    res.json({
      contractType: req.body.contractType || "",
      projectValue: req.body.projectValue || "",
      assessment: {
        riskRating: "HIGH",
        keyContractRisks: ["Payment timing and SOPA compliance", "Extension of time conditions precedent", "Variation valuation disputes", "Back charges and set-offs"],
        sopaObligations: "Payment claims must be served under SOPA Victoria by the reference date. Payment schedule must be given within 10 business days. Adjudication available if schedule not given or disputed amount not paid.",
        paymentRisks: "Ensure all payment claims include the magic words 'This is a payment claim made under the Building and Construction Industry Security of Payment Act 2002'. Retain copies of all delivery dockets, labour records, and subcontractor invoices.",
        timeRisks: "Extension of time claims must typically be submitted within 14–28 days of the event. Late submissions may be time-barred. Document all delay events contemporaneously.",
        variationRisks: "Most contracts require written instruction before performing variations. Oral instructions should be confirmed in writing immediately. Preserve right to payment for variations under SOPA even if written instruction missing.",
        securityObligations: "Performance security bonds must be maintained for the required period. Check return of retention and security obligations on practical completion and end of defects liability period.",
        disputeResolutionAdvice: "SOPA adjudication is available for payment disputes within strict timeframes. For broader disputes, exhaust contract dispute resolution steps before proceeding to court or arbitration.",
        onusOfProofIssues: "Contractor bears onus to demonstrate entitlement to payment, time extensions, and variations. Document all costs and delays with contemporaneous records.",
        recommendedContracts: ["AS 4000-1997 General Conditions of Contract", "AS 4902-2000 General Conditions of Contract for Design and Construct", "MBA/HIA for domestic building", "ABIC for architect-administered contracts"],
        preContractActions: ["Review and negotiate onerous clauses before signing", "Ensure payment terms comply with SOPA", "Confirm insurance requirements and arrange cover", "Engage solicitor for contracts above $500K"],
        applicableLegislation: ["Building and Construction Industry Security of Payment Act 2002 (Vic)", "Domestic Building Contracts Act 1995 (Vic)", "Australian Consumer Law", "Sale of Land Act 1962 (Vic)"],
        recommendation: "Obtain legal advice before signing contracts above $100K. Establish systems for timely payment claim submission, variation tracking, and delay documentation from day one.",
        summary: "Construction contract risk is elevated by complex time, payment, and variation provisions. Strict compliance with SOPA Victoria notice periods and contemporaneous record-keeping are essential to protect your entitlements.",
      },
    });
  }
});

// POST /contaminated-soil-record — Record contaminated soil excavation, classification, and disposal
app.post("/contaminated-soil-record", apiKeyAuth, async (req, res) => {
  try {
    const {
      projectId,
      recordRef,
      date,
      supervisor,
      location,
      excavationAreaM2,
      excavationDepthM,
      estimatedVolumeM3,
      soilDescription,
      contaminantsIdentified,
      contaminantConcentrations,
      epaClassification,
      samplesCollected,
      sampleCount,
      labRef,
      disposalLicensee,
      disposalFacility,
      epaFacilityLicenceNumber,
      wasteTrackingRef,
      truckCount,
      docketNumbers,
      contamResidualSoilManagement,
      remedialAction,
      postRemediationSamplingRequired,
      postRemediationRef,
      workerHazcomBriefed,
      dustSuppressionMeasures,
      groundwaterMonitoring,
      epaSiteManagementPlanRef,
      notes,
    } = req.body;

    if (!projectId || !date || !supervisor || !location || !epaClassification) {
      return res.status(400).json({ error: "projectId, date, supervisor, location, and epaClassification are required" });
    }

    const flags = [];
    // EPA Victoria: fill classifications CLEAN, PRESCRIBED INDUSTRIAL WASTE (PIW), CATEGORY A/B/C
    if (["PIW", "PRESCRIBED INDUSTRIAL WASTE"].includes(String(epaClassification || "").toUpperCase())) {
      flags.push("Soil classified as Prescribed Industrial Waste (PIW) — must be disposed to a licensed PIW facility. EPA Works Approval required for storage > 50 m³.");
    }
    if (["CATEGORY A", "CAT A", "A"].includes(String(epaClassification || "").toUpperCase())) {
      flags.push("Category A contaminated soil — restricted disposal, consult EPA Victoria and engage environmental consultant");
    }
    if (!disposalFacility) flags.push("Disposal facility not specified — contaminated soil must be disposed to an EPA-licensed facility per EPA Victoria Waste Management Policy");
    if (!wasteTrackingRef && !["CLEAN", "VIRGIN EXCAVATED NATURAL MATERIAL", "VENM"].includes(String(epaClassification || "").toUpperCase())) {
      flags.push("Waste tracking documentation not recorded — required for all regulated fill disposal under EPA Victoria regulations");
    }
    if (!workerHazcomBriefed) flags.push("Workers not briefed on contamination hazards — HAZCOM briefing required for all workers handling contaminated materials");

    const record = {
      project_id: sanitiseInput(projectId),
      record_ref: sanitiseInput(recordRef || `CS-${Date.now()}`),
      date,
      supervisor: sanitiseInput(supervisor),
      location: sanitiseInput(location),
      excavation_area_m2: excavationAreaM2 || null,
      excavation_depth_m: excavationDepthM || null,
      estimated_volume_m3: estimatedVolumeM3 || null,
      soil_description: sanitiseInput(soilDescription || ""),
      contaminants_identified: Array.isArray(contaminantsIdentified) ? contaminantsIdentified.map(c => sanitiseInput(c)) : [],
      contaminant_concentrations: sanitiseInput(contaminantConcentrations || ""),
      epa_classification: sanitiseInput(epaClassification),
      samples_collected: !!samplesCollected,
      sample_count: sampleCount || null,
      lab_ref: sanitiseInput(labRef || ""),
      disposal_licensee: sanitiseInput(disposalLicensee || ""),
      disposal_facility: sanitiseInput(disposalFacility || ""),
      epa_facility_licence_number: sanitiseInput(epaFacilityLicenceNumber || ""),
      waste_tracking_ref: sanitiseInput(wasteTrackingRef || ""),
      truck_count: truckCount || null,
      docket_numbers: Array.isArray(docketNumbers) ? docketNumbers.map(d => sanitiseInput(d)) : [],
      contam_residual_soil_management: sanitiseInput(contamResidualSoilManagement || ""),
      remedial_action: sanitiseInput(remedialAction || ""),
      post_remediation_sampling_required: !!postRemediationSamplingRequired,
      post_remediation_ref: sanitiseInput(postRemediationRef || ""),
      worker_hazcom_briefed: !!workerHazcomBriefed,
      dust_suppression_measures: sanitiseInput(dustSuppressionMeasures || ""),
      groundwater_monitoring: !!groundwaterMonitoring,
      epa_site_management_plan_ref: sanitiseInput(epaSiteManagementPlanRef || ""),
      flags,
      notes: sanitiseInput(notes || ""),
      created_at: new Date().toISOString(),
    };

    let saved = false;
    if (supabaseAdmin) {
      const { error } = await supabaseAdmin.from("contaminated_soil_records").insert(record);
      if (!error) saved = true;
    }

    res.json({
      epaClassification,
      flags,
      disposalRequired: !["CLEAN", "VENM", "VIRGIN EXCAVATED NATURAL MATERIAL"].includes(String(epaClassification || "").toUpperCase()),
      applicableRegulations: ["Environment Protection Act 2017 (Vic)", "EPA Victoria Waste Management Policy (Industrial Waste)", "National Environment Protection Measure (NEPM) for Site Contamination"],
      record,
      saved,
    });
  } catch (err) {
    console.error("/contaminated-soil-record error:", err.message);
    res.status(500).json({ error: "Failed to record contaminated soil" });
  }
});

// POST /glass-glazing-inspection — Record a glass and glazing installation inspection per AS 1288
app.post("/glass-glazing-inspection", apiKeyAuth, async (req, res) => {
  try {
    const {
      projectId,
      inspectionRef,
      date,
      inspector,
      location,
      glassType,
      glassThicknessMm,
      glassAreaM2,
      frameMaterial,
      frameType,
      safetyGlassRequired,
      safetyGlassComplied,
      safetyGlassMarkingPresent,
      glazingSystemRef,
      designWindPressure,
      actualGlassSpecification,
      edgeClearanceOk,
      faceClearanceOk,
      settingBlocksOk,
      sealantsOk,
      sealantType,
      weatherSealOk,
      thermalBreakInstalled,
      unitSealIntact,
      noCondensationWithinUnit,
      overallResult,
      defects,
      notes,
    } = req.body;

    if (!projectId || !date || !inspector || !glassType || !overallResult) {
      return res.status(400).json({ error: "projectId, date, inspector, glassType, and overallResult are required" });
    }

    const failures = [];
    if (safetyGlassRequired && !safetyGlassComplied) {
      failures.push("Safety glazing required but not installed — AS 1288 Table D1 requires safety glass in critical locations (doors, low-level panels, bathrooms, stairs)");
    }
    if (safetyGlassRequired && safetyGlassComplied && !safetyGlassMarkingPresent) {
      failures.push("Safety glass marking not visible — AS/NZS 4666 requires permanent marking identifying glass type on each pane");
    }
    if (!settingBlocksOk) failures.push("Setting blocks missing or incorrectly positioned — required per AS 1288 to prevent glass contact with frame at base");
    if (!sealantsOk) failures.push("Sealants non-compliant — inadequate sealant application can cause water ingress and premature glass failure");
    if (unitSealIntact === false) failures.push("Insulated glazing unit seal failed — fogging/condensation within unit, replacement required");

    const record = {
      project_id: sanitiseInput(projectId),
      inspection_ref: sanitiseInput(inspectionRef || `GG-${Date.now()}`),
      date,
      inspector: sanitiseInput(inspector),
      location: sanitiseInput(location || ""),
      glass_type: sanitiseInput(glassType),
      glass_thickness_mm: glassThicknessMm || null,
      glass_area_m2: glassAreaM2 || null,
      frame_material: sanitiseInput(frameMaterial || ""),
      frame_type: sanitiseInput(frameType || ""),
      safety_glass_required: !!safetyGlassRequired,
      safety_glass_complied: !!safetyGlassComplied,
      safety_glass_marking_present: safetyGlassRequired ? !!safetyGlassMarkingPresent : null,
      glazing_system_ref: sanitiseInput(glazingSystemRef || ""),
      design_wind_pressure: designWindPressure || null,
      actual_glass_specification: sanitiseInput(actualGlassSpecification || ""),
      edge_clearance_ok: !!edgeClearanceOk,
      face_clearance_ok: !!faceClearanceOk,
      setting_blocks_ok: !!settingBlocksOk,
      sealants_ok: !!sealantsOk,
      sealant_type: sanitiseInput(sealantType || ""),
      weather_seal_ok: !!weatherSealOk,
      thermal_break_installed: !!thermalBreakInstalled,
      unit_seal_intact: unitSealIntact !== undefined ? !!unitSealIntact : null,
      no_condensation_within_unit: noCondensationWithinUnit !== undefined ? !!noCondensationWithinUnit : null,
      overall_result: sanitiseInput(overallResult),
      defects: Array.isArray(defects) ? defects.map(d => sanitiseInput(d)) : [],
      failures,
      notes: sanitiseInput(notes || ""),
      created_at: new Date().toISOString(),
    };

    let saved = false;
    if (supabaseAdmin) {
      const { error } = await supabaseAdmin.from("glass_glazing_inspections").insert(record);
      if (!error) saved = true;
    }

    if (failures.length > 0) {
      return res.status(422).json({ passed: false, failures, message: "Glazing inspection failed. Rectify all failures before accepting the installation.", record, saved });
    }

    res.json({
      passed: true,
      inspectionRef: record.inspection_ref,
      failures: [],
      applicableStandards: ["AS 1288 Glass in buildings — selection and installation", "AS/NZS 4666 Insulating glass units", "NCC 2022 — safety glazing requirements"],
      record,
      saved,
    });
  } catch (err) {
    console.error("/glass-glazing-inspection error:", err.message);
    res.status(500).json({ error: "Failed to record glazing inspection" });
  }
});

// POST /ai-contaminated-land-assessment — AI assesses contaminated land risk and remediation requirements
app.post("/ai-contaminated-land-assessment", apiKeyAuth, async (req, res) => {
  try {
    const {
      siteAddress,
      previousLandUse,
      currentLandUse,
      proposedLandUse,
      contaminantsOfConcern,
      sampleResults,
      groundwaterDepthM,
      soilType,
      siteArea,
    } = req.body;

    if (!siteAddress || !previousLandUse || !proposedLandUse) {
      return res.status(400).json({ error: "siteAddress, previousLandUse, and proposedLandUse are required" });
    }

    const prompt = `You are an environmental consultant with expertise in Victorian contaminated land management, EPA Victoria guidance, the National Environment Protection Measure (NEPM) for Site Contamination, and the Environment Protection Act 2017 (Vic).

Assess contaminated land risk for:
- Site address: ${sanitiseInput(siteAddress)}
- Previous land use: ${sanitiseInput(previousLandUse)}
- Current land use: ${sanitiseInput(currentLandUse || "vacant")}
- Proposed land use: ${sanitiseInput(proposedLandUse)}
- Contaminants of concern: ${sanitiseInput(contaminantsOfConcern || "unknown")}
- Sample results: ${sanitiseInput(sampleResults || "not yet available")}
- Groundwater depth: ${sanitiseInput(String(groundwaterDepthM || "unknown"))} m
- Soil type: ${sanitiseInput(soilType || "not specified")}
- Site area: ${sanitiseInput(String(siteArea || "not specified"))} m²

Return a JSON object with:
{
  "riskLevel": "LOW|MEDIUM|HIGH|EXTREME",
  "phaseOneDeskStudyRecommended": boolean,
  "phaseTwoInvestigationRequired": boolean,
  "keyContaminantsOfConcern": [string],
  "receptorPathways": [string],
  "remediationApproachOptions": [string],
  "epaNotificationRequired": boolean,
  "siteAuditRequired": boolean,
  "certificateOfEnvironmentalAuditRequired": boolean,
  "healthRisks": string,
  "groundwaterImpact": string,
  "disposalConsiderations": string,
  "workerProtectionMeasures": [string],
  "applicableGuidance": [string],
  "recommendation": string,
  "summary": string
}`;

    const aiRes = await callOpenAIWithRetry({
      model: "gpt-4.1-mini",
      messages: [{ role: "user", content: prompt }],
      response_format: { type: "json_object" },
      max_tokens: 900,
    });
    usageStats.openaiCalls++;
    const assessment = JSON.parse(aiRes.choices[0].message.content);

    res.json({ siteAddress, previousLandUse, proposedLandUse, assessment });
  } catch (err) {
    console.error("/ai-contaminated-land-assessment error:", err.message);
    res.json({
      siteAddress: req.body.siteAddress || "",
      previousLandUse: req.body.previousLandUse || "",
      proposedLandUse: req.body.proposedLandUse || "",
      assessment: {
        riskLevel: "HIGH",
        phaseOneDeskStudyRecommended: true,
        phaseTwoInvestigationRequired: true,
        keyContaminantsOfConcern: ["Petroleum hydrocarbons (TPH, BTEX)", "Heavy metals (lead, arsenic)", "Chlorinated solvents (if industrial use)", "Asbestos in fill"],
        receptorPathways: ["Dermal contact during excavation", "Vapour intrusion to buildings", "Groundwater as drinking water receptor if shallow", "Dust inhalation during earthworks"],
        remediationApproachOptions: ["Excavation and disposal to licensed facility", "In-situ bioremediation for petroleum hydrocarbons", "Capping and risk-based land use controls", "Monitored natural attenuation for low-concentration plumes"],
        epaNotificationRequired: true,
        siteAuditRequired: true,
        certificateOfEnvironmentalAuditRequired: true,
        healthRisks: "High-sensitivity land uses (residential, childcare, schools) have lowest contamination criteria. Industrial/commercial uses have higher acceptable thresholds per NEPM Site Contamination.",
        groundwaterImpact: "If groundwater is within 3 m of surface, vapour intrusion and aquifer contamination are significant risks. Install monitoring wells and sample quarterly.",
        disposalConsiderations: "All excavated contaminated material must be characterised by laboratory analysis before disposal. PIW requires licensed PIW facility. VENM/clean fill may be reused or disposed to general fill sites.",
        workerProtectionMeasures: ["H&S management plan for contaminated site works", "HAZCOM briefing for all workers", "PPE: nitrile gloves, respirator (P2 for dust, organic vapour for solvents), Tyvek suits", "Air monitoring during excavation"],
        applicableGuidance: ["EPA Victoria Waste Management Policy (Industrial Waste) 2009", "NEPM Site Contamination 2013", "EPA Victoria Contaminated Land Guidance: Investigating and Remediating Contaminated Soil and Groundwater", "Environment Protection Act 2017 (Vic)"],
        recommendation: "Engage an EPA-accredited environmental auditor. Commission Phase 1 desk study immediately, followed by Phase 2 site investigation if previous industrial use is confirmed. Do not excavate without a site management plan.",
        summary: "Previous industrial land use creates elevated contamination risk. A site contamination investigation and EPA audit may be required before occupation or redevelopment of the site.",
      },
    });
  }
});

// POST /hvac-commissioning-record — Record HVAC system commissioning and air balancing per AS 1668 / AIRAH
app.post("/hvac-commissioning-record", apiKeyAuth, async (req, res) => {
  try {
    const {
      projectId,
      commissioningRef,
      date,
      contractor,
      technician,
      technicianLicenceNumber,
      buildingAddress,
      buildingClass,
      systemType,
      systemTag,
      designSupplyAirflowLs,
      measuredSupplyAirflowLs,
      designReturnAirflowLs,
      measuredReturnAirflowLs,
      designOutsideAirflowLs,
      measuredOutsideAirflowLs,
      staticPressurePa,
      fanSpeed,
      supplyAirTempC,
      returnAirTempC,
      condensingUnitPressureOk,
      refrigerantType,
      refrigerantChargeKg,
      refrigerantLeakTestOk,
      filterCondition,
      drainPanClear,
      co2SensorCalibrated,
      controlSequenceVerified,
      bmsIntegrated,
      thermostatSetPoints,
      noiseLevel,
      vibrationOk,
      overallResult,
      defects,
      certificateIssued,
      nextServiceDate,
      notes,
    } = req.body;

    if (!projectId || !date || !contractor || !systemType || !overallResult) {
      return res.status(400).json({ error: "projectId, date, contractor, systemType, and overallResult are required" });
    }

    const failures = [];
    const airflowTolerance = 0.1; // AS 1668.2: ±10% tolerance on design airflow
    if (designSupplyAirflowLs && measuredSupplyAirflowLs) {
      const deviation = Math.abs(Number(measuredSupplyAirflowLs) - Number(designSupplyAirflowLs)) / Number(designSupplyAirflowLs);
      if (deviation > airflowTolerance) failures.push(`Supply airflow ${measuredSupplyAirflowLs} L/s deviates ${(deviation * 100).toFixed(1)}% from design ${designSupplyAirflowLs} L/s — exceeds AS 1668.2 ±10% tolerance`);
    }
    if (designOutsideAirflowLs && measuredOutsideAirflowLs) {
      const ouAirDev = Math.abs(Number(measuredOutsideAirflowLs) - Number(designOutsideAirflowLs)) / Number(designOutsideAirflowLs);
      if (ouAirDev > 0.15) failures.push(`Outside air ${measuredOutsideAirflowLs} L/s is ${(ouAirDev * 100).toFixed(1)}% from design — IAQ/ventilation compliance risk`);
    }
    if (!refrigerantLeakTestOk && refrigerantType) failures.push("Refrigerant leak test failed or not completed — mandatory for all refrigerant systems under Australian Refrigeration Council regulations");
    if (!controlSequenceVerified) failures.push("Control sequence not verified — all control interlocks and sequences must be tested per AS 1668.1 commissioning requirements");
    if (overallResult === "FAIL") failures.push("HVAC commissioning FAILED — system must not be accepted until defects are rectified");

    const record = {
      project_id: sanitiseInput(projectId),
      commissioning_ref: sanitiseInput(commissioningRef || `HVAC-${Date.now()}`),
      date,
      contractor: sanitiseInput(contractor),
      technician: sanitiseInput(technician || ""),
      technician_licence_number: sanitiseInput(technicianLicenceNumber || ""),
      building_address: sanitiseInput(buildingAddress || ""),
      building_class: sanitiseInput(buildingClass || ""),
      system_type: sanitiseInput(systemType),
      system_tag: sanitiseInput(systemTag || ""),
      design_supply_airflow_ls: designSupplyAirflowLs || null,
      measured_supply_airflow_ls: measuredSupplyAirflowLs || null,
      design_return_airflow_ls: designReturnAirflowLs || null,
      measured_return_airflow_ls: measuredReturnAirflowLs || null,
      design_outside_airflow_ls: designOutsideAirflowLs || null,
      measured_outside_airflow_ls: measuredOutsideAirflowLs || null,
      static_pressure_pa: staticPressurePa || null,
      fan_speed: sanitiseInput(fanSpeed || ""),
      supply_air_temp_c: supplyAirTempC || null,
      return_air_temp_c: returnAirTempC || null,
      condensing_unit_pressure_ok: !!condensingUnitPressureOk,
      refrigerant_type: sanitiseInput(refrigerantType || ""),
      refrigerant_charge_kg: refrigerantChargeKg || null,
      refrigerant_leak_test_ok: !!refrigerantLeakTestOk,
      filter_condition: sanitiseInput(filterCondition || ""),
      drain_pan_clear: !!drainPanClear,
      co2_sensor_calibrated: !!co2SensorCalibrated,
      control_sequence_verified: !!controlSequenceVerified,
      bms_integrated: !!bmsIntegrated,
      thermostat_set_points: sanitiseInput(thermostatSetPoints || ""),
      noise_level: sanitiseInput(noiseLevel || ""),
      vibration_ok: !!vibrationOk,
      overall_result: sanitiseInput(overallResult),
      defects: Array.isArray(defects) ? defects.map(d => sanitiseInput(d)) : [],
      failures,
      certificate_issued: !!certificateIssued,
      next_service_date: nextServiceDate || null,
      notes: sanitiseInput(notes || ""),
      created_at: new Date().toISOString(),
    };

    let saved = false;
    if (supabaseAdmin) {
      const { error } = await supabaseAdmin.from("hvac_commissioning_records").insert(record);
      if (!error) saved = true;
    }

    if (failures.length > 0) {
      return res.status(422).json({ commissioned: false, failures, message: "HVAC commissioning failed. Rectify all defects and re-commission before handover.", record, saved });
    }

    res.json({
      commissioned: true,
      commissioningRef: record.commissioning_ref,
      failures: [],
      applicableStandards: ["AS 1668.1 The use of ventilation and air conditioning in buildings — fire and smoke control", "AS 1668.2 Ventilation design for indoor air contaminant control", "AIRAH DA19 Commissioning of HVAC systems"],
      record,
      saved,
    });
  } catch (err) {
    console.error("/hvac-commissioning-record error:", err.message);
    res.status(500).json({ error: "Failed to record HVAC commissioning" });
  }
});

// POST /acoustic-assessment — Record an acoustic/noise impact assessment
app.post("/acoustic-assessment", apiKeyAuth, async (req, res) => {
  try {
    const {
      projectId,
      assessmentRef,
      assessmentDate,
      assessor,
      assessorCompany,
      assessmentType,
      location,
      receiverType,
      noiseSource,
      measuredLaeqDb,
      measuredLaMaxDb,
      measuredL90Db,
      backgroundLevelDb,
      measurementPeriod,
      timeOfDay,
      dayNightIndicator,
      epaNoiseLimit,
      localCouncilLimit,
      exceedanceOccurred,
      exceedanceAmount,
      constructionNoiseCriteria,
      musicOrLowFrequency,
      vibrationIncluded,
      vibrationalVelocityMms,
      impactAssessmentResult,
      mitigationMeasures,
      complianceConclusion,
      notes,
    } = req.body;

    if (!projectId || !assessmentDate || !assessor || !assessmentType || !noiseSource) {
      return res.status(400).json({ error: "projectId, assessmentDate, assessor, assessmentType, and noiseSource are required" });
    }

    const flags = [];
    if (exceedanceOccurred) flags.push(`Noise exceedance: ${exceedanceAmount || "amount not specified"} dB above limit — noise mitigation measures required`);
    // EPA Victoria construction noise: residential 65 dB(A) LAeq (7am-6pm Mon-Fri), 65 dB(A) (7am-1pm Sat)
    if (measuredLaeqDb && epaNoiseLimit && Number(measuredLaeqDb) > Number(epaNoiseLimit)) {
      flags.push(`Measured LAeq ${measuredLaeqDb} dB(A) exceeds EPA limit ${epaNoiseLimit} dB(A)`);
    }
    if (musicOrLowFrequency) flags.push("Music or low-frequency noise present — additional assessment under EPA Victoria music noise criteria may be required");

    const record = {
      project_id: sanitiseInput(projectId),
      assessment_ref: sanitiseInput(assessmentRef || `AC-${Date.now()}`),
      assessment_date: assessmentDate,
      assessor: sanitiseInput(assessor),
      assessor_company: sanitiseInput(assessorCompany || ""),
      assessment_type: sanitiseInput(assessmentType),
      location: sanitiseInput(location || ""),
      receiver_type: sanitiseInput(receiverType || "residential"),
      noise_source: sanitiseInput(noiseSource),
      measured_laeq_db: measuredLaeqDb || null,
      measured_la_max_db: measuredLaMaxDb || null,
      measured_l90_db: measuredL90Db || null,
      background_level_db: backgroundLevelDb || null,
      measurement_period: sanitiseInput(measurementPeriod || ""),
      time_of_day: sanitiseInput(timeOfDay || ""),
      day_night_indicator: sanitiseInput(dayNightIndicator || "day"),
      epa_noise_limit: epaNoiseLimit || null,
      local_council_limit: localCouncilLimit || null,
      exceedance_occurred: !!exceedanceOccurred,
      exceedance_amount: exceedanceAmount || null,
      construction_noise_criteria: sanitiseInput(constructionNoiseCriteria || ""),
      music_or_low_frequency: !!musicOrLowFrequency,
      vibration_included: !!vibrationIncluded,
      vibrational_velocity_mms: vibrationalVelocityMms || null,
      impact_assessment_result: sanitiseInput(impactAssessmentResult || ""),
      mitigation_measures: sanitiseInput(mitigationMeasures || ""),
      compliance_conclusion: sanitiseInput(complianceConclusion || ""),
      flags,
      notes: sanitiseInput(notes || ""),
      created_at: new Date().toISOString(),
    };

    let saved = false;
    if (supabaseAdmin) {
      const { error } = await supabaseAdmin.from("acoustic_assessments").insert(record);
      if (!error) saved = true;
    }

    res.json({
      exceedanceOccurred: !!exceedanceOccurred,
      flags,
      constructionNoiseLimits: { weekday: "65 dB(A) LAeq 7am–6pm", saturday: "65 dB(A) LAeq 7am–1pm" },
      applicableGuidance: ["EPA Victoria Construction Noise Limit — Noise from Premises", "AS/NZS 1269 Occupational noise management", "EPA Victoria Noise Protocol 2021", "State Environment Protection Policy (Control of Noise from Commerce, Industry and Trade) N-1"],
      record,
      saved,
    });
  } catch (err) {
    console.error("/acoustic-assessment error:", err.message);
    res.status(500).json({ error: "Failed to record acoustic assessment" });
  }
});

