      urgent_repair_list: Array.isArray(urgentRepairList) ? urgentRepairList.map(r => sanitiseInput(r)) : [],
      recommended_actions: Array.isArray(recommendedActions) ? recommendedActions.map(a => sanitiseInput(a)) : [],
